-- Additional Premium Perfumes - Wave 2

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('07f00fec-3c8a-47eb-b84e-aef701cde070', 'Eros', 'Versace', 2012, 'Eau de Toilette', 'Mint, Green Apple, Lemon', 'Tonka Bean, Geranium, Ambroxan', 'Madagascar Vanilla, Vetiver, Oakmoss, Virginia Cedar', 'Eros is a fragrance for a strong, passionate man, who is master of himself. Fresh, woody and slightly oriental, the fragrance combines the sweetness of mint with Italian lemon zest, and tonka bean with Venezuelan ambroxan.', 'https://fimgs.net/mdimg/perfume/375x500.16657.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('b976d947-8633-43d6-a629-97f645a234e0', 'Le Male', 'Jean Paul Gaultier', 1995, 'Eau de Toilette', 'Lavender, Mint, Cardamom, Bergamot', 'Cinnamon, Cumin, Orange Blossom', 'Vanilla, Tonka Bean, Sandalwood, Cedar', 'Le Male celebrates the archetypal symbolic man. His weapon of seduction is his legendary fragrance. The powerfully fresh mint is heightened by the traditional lavender with its aromatic accents. The vanilla blends with the sensuous warmth of tonka bean.', 'https://fimgs.net/mdimg/perfume/375x500.124.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('471fe3a0-4a3e-4b4a-9d34-fd4bfa19cf8e', '1 Million', 'Paco Rabanne', 2008, 'Eau de Toilette', 'Grapefruit, Mint, Blood Mandarin', 'Cinnamon, Spicy Notes, Rose', 'Leather, Woody Notes, Amber, Patchouli', '1 Million is a spicy leather fragrance with blood mandarin, grapefruit, mint, and rose. The base combines leather, white wood, amber, and patchouli.', 'https://fimgs.net/mdimg/perfume/375x500.3747.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('d2d9dd56-6273-4478-9b60-8c90d937b907', 'Y Eau de Parfum', 'Yves Saint Laurent', 2018, 'Eau de Parfum', 'Apple, Ginger, Bergamot', 'Sage, Juniper Berries, Geranium', 'Amberwood, Tonka Bean, Cedar, Vetiver, Olibanum', 'Y EDP is the ultimate freedom cologne by Yves Saint Laurent. A white and dark fougère created for the fearless. This masculine perfume is for those who live their dreams for real.', 'https://fimgs.net/mdimg/perfume/375x500.52893.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('2df8db42-20bc-4c93-a502-0b25bd26e6d9', 'The One', 'Dolce & Gabbana', 2006, 'Eau de Parfum', 'Grapefruit, Coriander, Basil', 'Cardamom, Ginger, Orange Blossom', 'Cedarwood, Ambergris, Tobacco', 'The One is a sophisticated oriental woody fragrance with tobacco, amber, and spices. Elegant and masculine, perfect for evening wear.', 'https://fimgs.net/mdimg/perfume/375x500.2825.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('1ef578ac-2244-48c3-a6fd-3f568a181724', 'Acqua di Giò Profumo', 'Giorgio Armani', 2015, 'Eau de Parfum', 'Bergamot, Sea Notes', 'Geranium, Rosemary, Sage', 'Patchouli, Incense', 'Acqua di Giò Profumo is an aquatic aromatic fragrance that combines marine notes with incense, patchouli, and bergamot. Deeper and more intense than the original.', 'https://fimgs.net/mdimg/perfume/375x500.31675.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('0da9bcc6-0cf8-4943-bd25-a2b62f02388c', 'Bleu de Chanel Parfum', 'Chanel', 2018, 'Parfum', 'Lemon, Mint, Pink Pepper, Grapefruit', 'Ginger, Nutmeg, Jasmine', 'Incense, Cedar, Sandalwood, Tonka Bean, Patchouli', 'Bleu de Chanel Parfum is the most intense and sophisticated version of the Bleu line. A woody aromatic fragrance with sandalwood, cedar, and tonka bean.', 'https://fimgs.net/mdimg/perfume/375x500.46149.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('a5b02497-106f-44e8-a86b-9551a9509a32', 'Gentleman', 'Givenchy', 2017, 'Eau de Parfum', 'Pear, Cardamom, Lavender', 'Iris, Geranium', 'Patchouli, Leather, Vanilla, Tonka Bean', 'Gentleman is an aromatic woody fragrance with iris, patchouli, and vanilla. Modern elegance for the contemporary gentleman.', 'https://fimgs.net/mdimg/perfume/375x500.42157.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('49973cf8-741a-4f1d-ae79-f864aa5670ee', 'Good Girl', 'Carolina Herrera', 2016, 'Eau de Parfum', 'Almond, Coffee, Lemon', 'Tuberose, Jasmine Sambac, Orange Blossom', 'Tonka Bean, Cacao, Vanilla, Sandalwood, Musk', 'Good Girl is a captivating oriental floral fragrance. It''s sexy, bold, and intriguing with notes of jasmine, tuberose, tonka, and cocoa.', 'https://fimgs.net/mdimg/perfume/375x500.37328.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('1a70d2d2-f405-46f1-9f12-cb4a99a17998', 'Black Opium', 'Yves Saint Laurent', 2014, 'Eau de Parfum', 'Pear, Pink Pepper, Orange Blossom', 'Coffee, Jasmine, Bitter Almond, Licorice', 'Vanilla, Patchouli, Cedarwood, Cashmere Wood', 'Black Opium is a glowing floral and oriental fragrance with coffee, vanilla, and white flowers. Addictive and seductive.', 'https://fimgs.net/mdimg/perfume/375x500.22767.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('feaf7ba1-11aa-438c-93fa-d88b21a2315f', 'La Vie Est Belle', 'Lancôme', 2012, 'Eau de Parfum', 'Blackcurrant, Pear', 'Iris, Jasmine, Orange Blossom', 'Praline, Vanilla, Patchouli, Tonka Bean', 'La Vie Est Belle is a gourmand floral fragrance with iris, patchouli, and praline. The scent of happiness and freedom.', 'https://fimgs.net/mdimg/perfume/375x500.14982.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('9b61f6fa-b791-404d-8a1c-c2b79b418220', 'Flowerbomb', 'Viktor & Rolf', 2005, 'Eau de Parfum', 'Bergamot, Green Tea, Osmanthus', 'Sambac Jasmine, Orchid, Freesia, Rose', 'Patchouli, Musk', 'Flowerbomb is a floral explosion, a bouquet of sambac jasmine, centifolia rose, cattleya orchid, and ballerina freesia.', 'https://fimgs.net/mdimg/perfume/375x500.1459.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('91343cc4-165f-4dc2-9445-c58e0f6386f0', 'Coco Mademoiselle', 'Chanel', 2001, 'Eau de Parfum', 'Orange, Mandarin Orange, Orange Blossom, Bergamot', 'Mimosa, Jasmine, Turkish Rose, Ylang-Ylang', 'Tonka Bean, Opoponax, Vanilla, Vetiver, White Musk, Patchouli', 'Coco Mademoiselle is an oriental fragrance with a fresh citrus top, a sensual heart of rose and jasmine, and a warm base of patchouli and vanilla.', 'https://fimgs.net/mdimg/perfume/375x500.611.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('ec95846c-1f62-4c60-99ed-83802eae2346', 'Miss Dior', 'Dior', 2017, 'Eau de Parfum', 'Blood Orange, Mandarin Orange, Pink Pepper', 'Grasse Rose, Damask Rose, Peony', 'White Musk, Patchouli', 'Miss Dior is a floral fragrance with centifolia rose, Grasse rose, and Damascus rose. Couture and optimistic.', 'https://fimgs.net/mdimg/perfume/375x500.41727.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('7d7cdf18-3714-4a99-8012-49b96c15f4ec', 'Gucci Bloom', 'Gucci', 2017, 'Eau de Parfum', '', 'Natural Tuberose, Jasmine, Rangoon Creeper', '', 'Gucci Bloom is a white floral fragrance featuring tuberose, jasmine, and Rangoon creeper. A thriving garden of flowers.', 'https://fimgs.net/mdimg/perfume/375x500.42595.jpg');


